-- Ejecutar en Supabase → SQL Editor → Run
-- ============================================================
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE TABLE IF NOT EXISTS categories (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),name VARCHAR(100) NOT NULL,slug VARCHAR(100) UNIQUE NOT NULL,description TEXT,image_url TEXT,icon VARCHAR(50),is_active BOOLEAN DEFAULT true,sort_order INTEGER DEFAULT 0,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS products (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),category_id UUID REFERENCES categories(id) ON DELETE SET NULL,name VARCHAR(200) NOT NULL,slug VARCHAR(200) UNIQUE NOT NULL,tagline VARCHAR(300),description TEXT NOT NULL,story TEXT,price DECIMAL(10,2) NOT NULL,compare_price DECIMAL(10,2),cost_price DECIMAL(10,2),sku VARCHAR(50) UNIQUE,stock INTEGER DEFAULT 0,low_stock_alert INTEGER DEFAULT 5,weight_grams INTEGER,images JSONB DEFAULT '[]',ingredients TEXT[],allergens TEXT[],is_active BOOLEAN DEFAULT true,is_featured BOOLEAN DEFAULT false,is_new BOOLEAN DEFAULT false,tags TEXT[],meta_title VARCHAR(200),meta_description VARCHAR(300),points_reward INTEGER DEFAULT 0,is_subscription BOOLEAN DEFAULT false,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS customers (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL,email VARCHAR(255) UNIQUE NOT NULL,first_name VARCHAR(100),last_name VARCHAR(100),phone VARCHAR(20),whatsapp VARCHAR(20),address_line1 VARCHAR(200),address_line2 VARCHAR(200),city VARCHAR(100),state VARCHAR(100),region VARCHAR(100),postal_code VARCHAR(10),country VARCHAR(50) DEFAULT 'Chile',total_orders INTEGER DEFAULT 0,total_spent DECIMAL(12,2) DEFAULT 0,points INTEGER DEFAULT 0,membership VARCHAR(50) DEFAULT 'standard',notes TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS coupons (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),code VARCHAR(50) UNIQUE NOT NULL,description VARCHAR(200),type VARCHAR(20) NOT NULL CHECK (type IN ('percentage','fixed','free_shipping')),value DECIMAL(10,2) NOT NULL,min_order_amount DECIMAL(10,2) DEFAULT 0,max_discount DECIMAL(10,2),usage_limit INTEGER,usage_count INTEGER DEFAULT 0,user_limit INTEGER DEFAULT 1,is_active BOOLEAN DEFAULT true,starts_at TIMESTAMPTZ DEFAULT NOW(),expires_at TIMESTAMPTZ,applicable_to VARCHAR(20) DEFAULT 'all',applicable_ids UUID[],created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS orders (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),order_number VARCHAR(20) UNIQUE NOT NULL,customer_id UUID REFERENCES customers(id),status VARCHAR(30) DEFAULT 'pending' CHECK (status IN ('pending','confirmed','processing','shipped','delivered','cancelled','refunded')),payment_status VARCHAR(20) DEFAULT 'pending' CHECK (payment_status IN ('pending','paid','failed','refunded','partial')),subtotal DECIMAL(10,2) NOT NULL,discount_amount DECIMAL(10,2) DEFAULT 0,shipping_amount DECIMAL(10,2) DEFAULT 0,tax_amount DECIMAL(10,2) DEFAULT 0,total DECIMAL(10,2) NOT NULL,coupon_id UUID REFERENCES coupons(id),coupon_code VARCHAR(50),payment_method VARCHAR(50),payment_reference VARCHAR(200),mp_preference_id VARCHAR(200),shipping_method VARCHAR(50),tracking_number VARCHAR(100),shipping_address JSONB,shipping_zone_id UUID,shipping_zone_name VARCHAR(100),delivery_date DATE,delivery_time VARCHAR(20),customer_email VARCHAR(255),customer_phone VARCHAR(20),customer_name VARCHAR(200),notes TEXT,admin_notes TEXT,paid_at TIMESTAMPTZ,shipped_at TIMESTAMPTZ,delivered_at TIMESTAMPTZ,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
ALTER TABLE orders ADD COLUMN IF NOT EXISTS delivery_date DATE;
ALTER TABLE orders ADD COLUMN IF NOT EXISTS delivery_time VARCHAR(20);
ALTER TABLE orders ADD COLUMN IF NOT EXISTS shipping_zone_id UUID;
ALTER TABLE orders ADD COLUMN IF NOT EXISTS shipping_zone_name VARCHAR(100);
ALTER TABLE customers ADD COLUMN IF NOT EXISTS region VARCHAR(100);
CREATE TABLE IF NOT EXISTS order_items (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),order_id UUID NOT NULL REFERENCES orders(id) ON DELETE CASCADE,product_id UUID REFERENCES products(id) ON DELETE SET NULL,product_name VARCHAR(200) NOT NULL,product_sku VARCHAR(50),product_image TEXT,unit_price DECIMAL(10,2) NOT NULL,quantity INTEGER NOT NULL CHECK (quantity > 0),subtotal DECIMAL(10,2) NOT NULL,created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS blog_posts (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),title VARCHAR(300) NOT NULL,slug VARCHAR(300) UNIQUE NOT NULL,excerpt TEXT,content TEXT NOT NULL,cover_image TEXT,author_name VARCHAR(100) DEFAULT 'MAKANGRU',category VARCHAR(100),tags TEXT[],is_published BOOLEAN DEFAULT false,published_at TIMESTAMPTZ,meta_title VARCHAR(200),meta_description VARCHAR(300),read_time_minutes INTEGER,views INTEGER DEFAULT 0,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS contact_messages (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),name VARCHAR(200) NOT NULL,email VARCHAR(255) NOT NULL,phone VARCHAR(20),subject VARCHAR(200),message TEXT NOT NULL,is_read BOOLEAN DEFAULT false,created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS shipping_zones (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),name VARCHAR(100) NOT NULL,regions TEXT[] NOT NULL,price DECIMAL(10,2) NOT NULL,free_above DECIMAL(10,2),min_days INTEGER DEFAULT 1,max_days INTEGER DEFAULT 3,is_active BOOLEAN DEFAULT true,sort_order INTEGER DEFAULT 0,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS delivery_settings (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),enabled_weekdays INTEGER[] DEFAULT '{2,4,6}',min_advance_days INTEGER DEFAULT 2,max_advance_days INTEGER DEFAULT 21,cutoff_hour INTEGER DEFAULT 12,delivery_message TEXT DEFAULT 'Elige tu fecha de entrega preferida ✦',max_orders_per_day INTEGER DEFAULT 0,updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS blocked_delivery_dates (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),date DATE UNIQUE NOT NULL,reason VARCHAR(200),created_at TIMESTAMPTZ DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_products_slug ON products(slug);
CREATE INDEX IF NOT EXISTS idx_products_active ON products(is_active);
CREATE INDEX IF NOT EXISTS idx_products_featured ON products(is_featured);
CREATE INDEX IF NOT EXISTS idx_orders_status ON orders(status);
CREATE INDEX IF NOT EXISTS idx_orders_created ON orders(created_at DESC);
CREATE INDEX IF NOT EXISTS idx_customers_email ON customers(email);
CREATE OR REPLACE FUNCTION update_updated_at() RETURNS TRIGGER AS $$ BEGIN NEW.updated_at = NOW(); RETURN NEW; END; $$ LANGUAGE plpgsql;
DROP TRIGGER IF EXISTS trg_products_updated ON products; CREATE TRIGGER trg_products_updated BEFORE UPDATE ON products FOR EACH ROW EXECUTE FUNCTION update_updated_at();
DROP TRIGGER IF EXISTS trg_categories_updated ON categories; CREATE TRIGGER trg_categories_updated BEFORE UPDATE ON categories FOR EACH ROW EXECUTE FUNCTION update_updated_at();
DROP TRIGGER IF EXISTS trg_customers_updated ON customers; CREATE TRIGGER trg_customers_updated BEFORE UPDATE ON customers FOR EACH ROW EXECUTE FUNCTION update_updated_at();
DROP TRIGGER IF EXISTS trg_orders_updated ON orders; CREATE TRIGGER trg_orders_updated BEFORE UPDATE ON orders FOR EACH ROW EXECUTE FUNCTION update_updated_at();
DROP TRIGGER IF EXISTS trg_shipping_updated ON shipping_zones; CREATE TRIGGER trg_shipping_updated BEFORE UPDATE ON shipping_zones FOR EACH ROW EXECUTE FUNCTION update_updated_at();
CREATE OR REPLACE FUNCTION increment_coupon_usage(coupon_id UUID) RETURNS VOID AS $$ BEGIN UPDATE coupons SET usage_count = usage_count + 1 WHERE id = coupon_id; END; $$ LANGUAGE plpgsql SECURITY DEFINER;
CREATE OR REPLACE FUNCTION update_customer_stats(p_customer_id UUID) RETURNS VOID AS $$ BEGIN UPDATE customers SET total_orders=(SELECT COUNT(*) FROM orders WHERE customer_id=p_customer_id AND payment_status='paid'),total_spent=(SELECT COALESCE(SUM(total),0) FROM orders WHERE customer_id=p_customer_id AND payment_status='paid') WHERE id=p_customer_id; END; $$ LANGUAGE plpgsql SECURITY DEFINER;
ALTER TABLE products ENABLE ROW LEVEL SECURITY;
ALTER TABLE categories ENABLE ROW LEVEL SECURITY;
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE customers ENABLE ROW LEVEL SECURITY;
ALTER TABLE coupons ENABLE ROW LEVEL SECURITY;
ALTER TABLE blog_posts ENABLE ROW LEVEL SECURITY;
ALTER TABLE contact_messages ENABLE ROW LEVEL SECURITY;
ALTER TABLE order_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE shipping_zones ENABLE ROW LEVEL SECURITY;
ALTER TABLE delivery_settings ENABLE ROW LEVEL SECURITY;
ALTER TABLE blocked_delivery_dates ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "products_public_read" ON products; CREATE POLICY "products_public_read" ON products FOR SELECT USING (is_active = true);
DROP POLICY IF EXISTS "categories_public_read" ON categories; CREATE POLICY "categories_public_read" ON categories FOR SELECT USING (is_active = true);
DROP POLICY IF EXISTS "blog_public_read" ON blog_posts; CREATE POLICY "blog_public_read" ON blog_posts FOR SELECT USING (is_published = true);
DROP POLICY IF EXISTS "shipping_zones_public_read" ON shipping_zones; CREATE POLICY "shipping_zones_public_read" ON shipping_zones FOR SELECT USING (is_active = true);
DROP POLICY IF EXISTS "delivery_settings_public_read" ON delivery_settings; CREATE POLICY "delivery_settings_public_read" ON delivery_settings FOR SELECT USING (true);
DROP POLICY IF EXISTS "blocked_dates_public_read" ON blocked_delivery_dates; CREATE POLICY "blocked_dates_public_read" ON blocked_delivery_dates FOR SELECT USING (true);
